package retrofit.http;

import java.io.IOException;
import java.io.OutputStream;
import java.io.UnsupportedEncodingException;
import java.lang.annotation.Annotation;
import java.lang.reflect.Array;
import java.lang.reflect.Method;
import java.lang.reflect.Type;
import java.net.HttpURLConnection;
import java.net.URI;
import java.net.URLEncoder;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import retrofit.client.Client;
import retrofit.client.Header;
import retrofit.client.Request;
import retrofit.converter.Converter;
import retrofit.mime.FormUrlEncodedTypedOutput;
import retrofit.mime.MultipartTypedOutput;
import retrofit.mime.TypedByteArray;
import retrofit.mime.TypedOutput;

final class RequestBuilder {
  private static final String ENC = "UTF-8";
  private static final String PATH_PARAMETER = "[a-zA-Z][a-zA-Z0-9_-]*";
  private static final Pattern PATH_PARAMS = Pattern.compile("\\{(" + PATH_PARAMETER + ")\\}");

  private final String method;
  private final String apiUrl;
  private final Converter converter;
  private final Annotation[] paramAnnotations;
  private final boolean isMultipart;
  private final boolean isFormEncoded;
  private final Method methodInfo;
  private final Type responseType;


  private String relativeUrl;
  private Header[] headers;
  private Object[] args;
  private TypedOutput body;

  RequestBuilder(String method, String apiUrl, String relativeUrl, Header[] headers,
      Annotation[] paramAnnotations, boolean isMultipart, boolean isFormEncoded, Method methodInfo, Type responseType, Converter converter) {
    this.method = method;
    this.apiUrl = apiUrl;
    this.relativeUrl = relativeUrl;
    this.headers = headers;
    this.paramAnnotations = paramAnnotations;
    this.isMultipart = isMultipart;
    this.isFormEncoded = isFormEncoded;
    this.methodInfo = methodInfo;
      this.responseType = responseType;
    this.converter = converter;

  }

  private static String getUrl(String apiUrl, String relativeUrl, Object[] args,
      Annotation[] paramAnnotations) {
    if (relativeUrl != null && !relativeUrl.startsWith("/")) {
      StringBuilder url = new StringBuilder(apiUrl);
      if (!apiUrl.endsWith("/")) {
        url.append('/');
      }
      url.append(relativeUrl);
      return getPath(url.toString(), args, paramAnnotations);
    } else {
      return getPath(apiUrl, args, paramAnnotations);
    }
  }
  private static String getPath(String path, Object[] args, Annotation[] paramAnnotations) {
    Matcher matcher = PATH_PARAMS.matcher(path);
    StringBuffer result = new StringBuffer();
    int argIndex = 0;
    while (matcher.find()) {
      String name = matcher.group(1);
      String value = null;
      for(int i = argIndex; i < paramAnnotations.length ; i++) {
          if (paramAnnotations[i] instanceof Path) {
            Path pathAnnotation = (Path) paramAnnotations[i];
              if(name.equals(pathAnnotation.value())) {
                value = String.valueOf(args[i]);
                  argIndex = i + 1;
                  break;
             }
          }
      }

      try {
            if (value == null) {
                throw new IllegalArgumentException("Path parameter " + name + " not found in Method args.");
            }
          matcher.appendReplacement(result, URLEncoder.encode(value, ENC).replace("+", "%20"));
        } catch (UnsupportedEncodingException e) {
          throw new RuntimeException(
              "Unable to convert path parameter \"" + value + "\" to UTF-8." + e.getMessage());
        }
    }
    matcher.appendTail(result);
    return result.toString();
  }

  Request build(Object[] args) {
    this.args = args;
    String url = getUrl(apiUrl, relativeUrl, args, paramAnnotations);

    if (method.equals("GET")) {
      return new Request(method, url, headers);
    }
    if (body == null && isFormEncoded) {
      createFormEncodedBody();
    }
    if(body == null && isMultipart){
      createMultipartBody();
    }

    return new Request(method, url, headers, body);
  }

  private void createMultipartBody() {
    MultipartTypedOutput multipartTypedOutput = new MultipartTypedOutput();
    for (int i = 0; i < paramAnnotations.length; i++) {
      Annotation annotation = paramAnnotations[i];
      if (annotation instanceof Part) {
        Part part = (Part) annotation;
        String name = part.value();
        Object value = args[i];
        if (value == null) {
          continue;
        }
        if (value instanceof TypedOutput) {
          multipartTypedOutput.addPart(name, (TypedOutput) value);
        } else {
          String mimeType = part.mimeType();
          if(mimeType.equals("")){
            mimeType = "text/plain; charset=UTF-8";
          }
          multipartTypedOutput.addPart(name, new TypedByteArray(mimeType, String.valueOf(value).getBytes()));
        }
      }
    }
    this.body = multipartTypedOutput;
  }

  private void createFormEncodedBody() {
    FormUrlEncodedTypedOutput body = new FormUrlEncodedTypedOutput();
    for (int i = 0; i < paramAnnotations.length; i++) {
      Annotation annotation = paramAnnotations[i];
      if (annotation instanceof Field) {
        Field field = (Field) annotation;
        String name = field.value();
        if (name != null) {
            Object value = args[i];
            if(value != null){
            body.addField(name, String.valueOf(value));
            }
        }
      } else if(annotation instanceof FieldMap) {
        Object value = args[i];
          if(value instanceof Map) {
              Map<?, ?> map = (Map<?, ?>) value;
                for(Map.Entry<?, ?> entry : map.entrySet()) {
                    if(entry.getKey() != null && entry.getValue() != null){
                        body.addField(String.valueOf(entry.getKey()), String.valueOf(entry.getValue()));
                    }
                  }
          }
      }
    }
    this.body = body;
  }

    void setBody(TypedOutput body){
        this.body = body;
    }

  void setRelativeUrl(String relativeUrl) {
    this.relativeUrl = relativeUrl;
  }

  void setHeaders(Header[] headers) {
    this.headers = headers;
  }

}
