public void clearCache() {
  lock.writeLock().lock();
  try {
    if (whiteList != null) {
      whiteList = null;
    }
  }  finally {
    lock.writeLock().unlock();
  }
}

public boolean whiteContains(String sql) {
  lock.readLock().lock();
  try {
    if (whiteList == null) {
      return false;
    }
    return whiteList.get(sql) != null;
  }  finally {
