```javascript
import React from 'react';
import { Table, Button, Input, message, Popconfirm, Divider } from 'antd';
import { SearchOutlined, PlusOutlined } from '@ant-design/icons';
import './ListeningToQuery.less';
import Service from '../../../service';
import CreateModal from './CreateModal';
import UpdateModal from './UpdateModal';

const { Search } = Input;
class ListeningToQuery extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            dataSource: [],
            loading: false,
            total: 0,
            visible: false,
            updateVisible: false,
            selectRecord: {},
            queryParams: {
                pageSize: 10,
                pageNum: 1,
                name: '',
            },
        };
        this.columns = [
            {
                title: '序号',
                dataIndex: 'index',
                key: 'index',
                render: (text, record, index) => `${index + 1}`,
            },
            {
                title: '配置名称',
                dataIndex: 'name',
                key: 'name',
            },
            {
                title: '查询SQL',
                dataIndex: 'querySQL',
                key: 'querySQL',
            },
            {
                title: '描述',
                dataIndex: 'description',
                key: 'description',
            },
            {
                title: '创建时间',
                dataIndex: 'gmtCreate',
                key: 'gmtCreate',
            },
            {
                title: '操作',
                key: 'action',
                render: (text, record) => (
                    <span>
                        <a
                            onClick={() => {
                                this.update(record);
                            }}
                        >
                            修改
                        </a>
                        <Divider type="vertical" />
                        <Popconfirm
                            title="确认删除?"
                            onConfirm={() => this.delete(record.id)}
                            okText="Yes"
                            cancelText="No"
                        >
                            <a>删除</a>
                        </Popconfirm>
                    </span>
                ),
            },
        ];
    }

    componentDidMount() {
        this.queryList();
    }

    componentWillUnmount() {
        this.setState = (state, callback) => {
            return;
        };
    }
    update = (record) => {
        this.setState({
            updateVisible: true,
            selectRecord: record,
        });
    };
    delete = async (id) => {
        const result = await Service.deleteListeningToQuery(id);
        if (result.code === 200) {
            message.success('删除成功');
            this.queryList();
        } else {
            message.error(result.msg);
        }
    };
    queryList = async () => {
        this.setState({
            loading: true,
        });
        const { queryParams } = this.state;
        const result = await Service.queryListeningToQuery(queryParams);
        if (result.code === 200) {
            let dataSoureTmp = result.data.records || [];
            dataSoureTmp = dataSoureTmp.map((item) => {
                return {
                    ...item,
                    key: item.id,
                };
            });
            const data = result.data;
            this.setState({
                dataSource: dataSoureTmp || [],
                total: dataSoureTmp.length || 0
            });
        }
        this.setState({
            loading: false,
        });
    };
    handleSearch = (value) => {
        const { queryParams } = this.state;
        queryParams.name = value;
        queryParams.pageNum = 1;
        this.setState(
            {
                queryParams,
            },
            () => {
                this.queryList();
            }
        );
    };
    handleTableChange = (pagination) => {
        const { queryParams } = this.state;
        queryParams.pageNum = pagination.current;
        queryParams.pageSize = pagination.pageSize;
        this.setState(
            {
                queryParams,
            },
            () => {
                this.queryList();
            }
        );
    };
    create = () => {
        this.setState({
            visible: true,
        });
    };
    onCancel = () => {
        this.setState({
            visible: false,
        });
    };
    onUpdateCancel = () => {
        this.setState({
            updateVisible: false,
        });
    };
    onCreateSuccess = () => {
        this.setState({
            visible: false,
        });
        this.queryList();
    };
    onUpdateSuccess = () => {
        this.setState({
            updateVisible: false,
        });
        this.queryList();
    };
    render() {
        const { dataSource, loading, total, visible, updateVisible, selectRecord, queryParams } =
            this.state;
        return (
            <div className="listening-to-query-container">
                <div className="table-header">
                    <Search
                        placeholder="请输入配置名称"
                        onSearch={this.handleSearch}
                        style={{ width: 240 }}
                        suffix={<SearchOutlined />}
                    />
                    <Button type="primary" icon={<PlusOutlined />} onClick={this.create}>
                        新建配置
                    </Button>
                </div>
                <Table
                    columns={this.columns}
                    dataSource={dataSource}
                    loading={loading}
                    pagination={{
                        total,
                        current: queryParams.pageNum,
                        pageSize: queryParams.pageSize,
                        showSizeChanger: true,
                        showTotal: (total) => `总共 ${total} 条`,
                    }}
                    onChange={this.handleTableChange}
                />
                {visible ? (
                    <CreateModal
                        visible={visible}
                        onCancel={this.onCancel}
                        onCreateSuccess={this.onCreateSuccess}
                    />
                ) : null}
                {updateVisible ? (
                    <UpdateModal
                        visible={updateVisible}
                        onCancel={this.onUpdateCancel}
                        onUpdateSuccess={this.onUpdateSuccess}
                        record={selectRecord}
                    />
                ) : null}
            </div>
        );
    }
}

export default ListeningToQuery;

```

