```groovy
package filters.route

import com.netflix.zuul.ZuulFilter
import com.netflix.zuul.context.RequestContext
import org.apache.http.HttpHost
import org.apache.http.client.HttpClient
import org.apache.http.client.methods.BasicHttpRequest
import org.apache.http.client.methods.HttpPost
import org.apache.http.client.methods.HttpPut
import org.apache.http.entity.InputStreamEntity
import org.apache.http.impl.client.HttpClientBuilder
import org.apache.http.HttpResponse
import org.apache.http.util.EntityUtils
import javax.servlet.http.HttpServletRequest
import java.net.URI
import java.net.URLDecoder
import java.nio.charset.StandardCharsets

class SimpleHostRoutingFilter extends ZuulFilter {
    @Override
    String filterType() {
        return "route";
    }

    @Override
    int filterOrder() {
        return 1;
    }

    @Override
    boolean shouldFilter() {
        return true;
    }

    @Override
    Object run() {
        RequestContext context = RequestContext.currentContext
        HttpServletRequest request = context.getRequest()

        HttpClient httpclient = getHttpClient();
        HttpHost httpHost = getHttpHost();

        HttpResponse zuulResponse = null;

        try {
           zuulResponse = forward(httpclient, httpHost, request)
           setResponse(zuulResponse)
        } catch(Exception e) {
           e.printStackTrace()
        } finally {
            if(zuulResponse != null) {
                EntityUtils.consume(zuulResponse.getEntity());
            }

        }

        return null
    }

    void setResponse(HttpResponse httpResponse) {
        RequestContext context = RequestContext.currentContext;
        context.setResponseStatusCode(httpResponse.getStatusLine().getStatusCode());
        context.setResponseBody(EntityUtils.toString(httpResponse.getEntity()))
        context.getResponse().setContentType(httpResponse.getEntity().getContentType().getValue())
    }

    HttpResponse forward(HttpClient httpclient, HttpHost httpHost, HttpServletRequest request) {
        String verb = request.getMethod();
        String uri = request.getRequestURI();
        InputStream requestEntity = request.getInputStream();

        def httpRequest;

        switch (verb) {
            case 'POST':
                httpRequest = new HttpPost(uri + getSanitizedQueryString())
                InputStreamEntity entity = new InputStreamEntity(requestEntity, request.getContentLength())
                httpRequest.setEntity(entity)
                break
            case 'PUT':
                httpRequest = new HttpPut(uri + getSanitizedQueryString())
                InputStreamEntity entity = new InputStreamEntity(requestEntity, request.getContentLength())
                httpRequest.setEntity(entity)
                break;
            default:
                httpRequest = new BasicHttpRequest(verb, uri + getSanitizedQueryString())
        }

        try {
            httpRequest.addHeader("Content-Type", request.getContentType());
            def headers = request.getHeaderNames().iterator();
            while (headers.hasNext()) {
                def headerName = headers.next();
                if (!headerName.toLowerCase().equals("content-type")) {
                    def headerValues = request.getHeaders(headerName).iterator()
                    while (headerValues.hasNext()) {
                        httpRequest.addHeader(headerName, headerValues.next())
                    }
                }

            }
        } catch(Exception e) {
            e.printStackTrace();
        }

        return httpclient.execute(httpHost, httpRequest);
    }

    String getSanitizedQueryString() {
        String encoding = "UTF-8"
        String currentQueryString = getQueryString()
        if (currentQueryString.equals("")) {
            return ""
        }

        String decodedQueryString = URLDecoder.decode(currentQueryString, encoding)
        return new URI(null, null, null, decodedQueryString, null).toString()
    }

    String getQueryString() {
        HttpServletRequest request = RequestContext.currentContext.getRequest();
        String query = request.getQueryString()
        return (query != null) ? query : "";
    }

    HttpHost getHttpHost() {
        RequestContext context = RequestContext.currentContext;
        String scheme = context.getRequest().getScheme()
        String host = context.getRouteHost().getHost()
        int port = context.getRouteHost().getPort()
        return new HttpHost(host, port, scheme)
    }


    HttpClient getHttpClient() {
       return  HttpClientBuilder.create().build();
    }
}
```

