    private final String sql; 

    SqlMethod(String method, String desc, String sql) {
        this.method = method;
        this.desc = desc;
        this.sql = sql;
    }


    public String getMethod() {
        return method;
    }


    public String getDesc() {
        return desc;
    }


    public String getSql() {
        return sql;
    }
